arguments.command:
# Find the symbols surrounding these addresses
aarch64-linux-gnu-nm -n /tmp/libmonosgen_debug.so 2>/dev/null | awk '
$1 ~ /^[0-9a-f]+$/ {
    addr = strtonum("0x"$1);
    if (addr <= 0x2f4b20) { prev_addr=$1; prev_name=$3; prev_type=$2 }
    if (addr > 0x2f4b20 && !found1) { print "0x2f4b20 -> " prev_name " + " sprintf("0x%x", 0x2f4b20 - strtonum("0x"prev_addr)) " (prev: " prev_addr " " prev_type " " prev_name ", next: " $1 " " $2 " " $3 ")"; found1=1 }
    if (addr <= 0x2f4c84) { prev_addr2=$1; prev_name2=$3 }
    if (addr > 0x2f4c84 && !found2) { print "0x2f4c84 -> " prev_name2 " + " sprintf("0x%x", 0x2f4c84 - strtonum("0x"prev_addr2)) " (prev: " prev_addr2 " " $2 " " prev_name2 ", next: " $1 " " $2 " " $3 ")"; found2=1 }
}'

