arguments.command:
# Try with more verbose options to get inline frames
aarch64-linux-gnu-addr2line -C -f -i -e /tmp/libmonosgen_debug.so 0x2f4b20 0x2f4c84
echo "==="
# Check what function these fall in
aarch64-linux-gnu-nm -n /tmp/libmonosgen_debug.so 2>/dev/null | awk '
$1 ~ /^[0-9a-f]+$/ && ($2 == "t" || $2 == "T") {
    addr = strtonum("0x"$1);
    if (addr <= 0x2f4b20) { prev_addr=$1; prev_name=$3 }
    if (addr > 0x2f4b20 && !found1) { print "0x2f4b20 is in: " prev_name " (at 0x" prev_addr ")"; found1=1 }
    if (addr <= 0x2f4c84) { prev_addr2=$1; prev_name2=$3 }
    if (addr > 0x2f4c84 && !found2) { print "0x2f4c84 is in: " prev_name2 " (at 0x" prev_addr2 ")"; found2=1 }
}'

